    singularValues[i] = Math.sqrt(eigenValues[i]);
}

// Now apply numerical rank determination - for singular/ill-conditioned matrices
// determine effective rank based on threshold
final double threshold = Math.max(m, n) * Math.ulp(singularValues.length > 0 ? singularValues[0] : 0.0);
int effectiveRank = 0;
for (int i = 0; i < p; ++i) {
    if (singularValues[i] > threshold) {
        effectiveRank++;
    } else {
        // Set effectively zero singular values to 0
        singularValues[i] = 0.0;
    }
}
// If we reduced the rank, we need to resize the singular values array
if (effectiveRank < p) {
    double[] tempSingularValues = new double[effectiveRank];
    System.arraycopy(singularValues, 0, tempSingularValues, 0, effectiveRank);
    singularValues = tempSingularValues;
}

